    html: "<div class=\"content-page works-detail-page\">\n  <h1 style=\"font-size: 24px; font-weight: bold; margin-bottom: 20px;\">Workshop: Weekly Weakly</h1>\n\n  <div style=\"margin-bottom: 40px;\">\n    <img src=\"/images/073f40_8ccb53e25cfd4bdcb82fe37ee7f8880e_mv2.png\" style=\"width: 100%; max-width: 100%; height: auto; display: block;\" alt=\"Workshop: Weekly Weakly\" loading=\"lazy\">\n  </div>\n\n  <div style=\"margin-bottom: 40px;\">\n    <img src=\"/images/073f40_c83f116384e74ea2855cc6d31a9e3586_mv2.jpg\" style=\"width: 100%; max-width: 100%; height: auto; display: block;\" alt=\"Workshop: Weekly Weakly\" loading=\"lazy\">\n  </div>\n\n  <div style=\"margin-bottom: 40px;\">\n    <img src=\"/images/073f40_32376a4bbf6349e7afd8ed1666e516b2_mv2.jpg\" style=\"width: 100%; max-width: 100%; height: auto; display: block;\" alt=\"Workshop: Weekly Weakly\" loading=\"lazy\">\n  </div>\n\n</div>"
